// Phase 29-05: thin caller -- the live-schema + v3-data-model + keyword-override
// guidance string, and the "Smart Overrides" keyword-matching logic, now live
// entirely in data-service's /context/assemble (dg_context.assemble_context()
// + its deterministic _match_shape_ids() keyword matcher, Plan 29-03). This
// node only string-joins the assembled context dict into the final prompt --
// it asks for RAW Cypher text (no JSON wrapper), matching what
// POST /context/generate-cypher's validate_cypher() expects as input.
const input = $items("Set Input Defaults")[0].json;
const context = $json;
const promptText = (input.prompt_text || '').trim();
if (!promptText) {
  throw new Error('prompt is required');
}

const projectNote = input.project_name
  ? `MANDATORY: You MUST add r.project = $project to EVERY query that touches Rule, Atom, Var, or Literal nodes. The active project is \"${input.project_name}\". Never omit this filter -- results must be scoped to this project only.`
  : 'Only add a project filter if the user explicitly mentions a project.';

const prompt = [
  'You are a Neo4j Cypher expert.',
  'Generate a single read-only Cypher query that answers the user question.',
  'Output Cypher only -- no JSON, no markdown fences, no commentary.',
  'STRICT RULE: Use ONLY the labels, relationship types, and property keys described in the CONTEXT below.',
  '',
  'CONTEXT (deterministically assembled by /context/assemble -- schema layers, SWRL conventions, matched Cypher catalog shape(s), and known existing entities):',
  JSON.stringify({
    ontograph: context.ontograph,
    metagraph: context.metagraph,
    validgraph: context.validgraph,
    swrl_conventions: context.swrl_conventions,
    selected_cypher_shapes: context.selected_cypher_shapes,
    existing_entities: context.existing_entities
  }),
  '',
  `- ${projectNote}`,
  '- Always include LIMIT 50 unless the user explicitly asks for all results.',
  '',
  'Question:',
  promptText
].join('\n');

return [{ json: { ...input, cypher_prompt: prompt } }];

// Phase 29-05: thin caller -- bracket-nesting / label-rel-prop allow-list
// checks and the ad hoc project-filter string-injection no longer live here.
// POST /context/generate-cypher (dg_context.generate_validated_cypher(), Plan
// 29-04) already ran validate_cypher() (schema + read-only verb policy) with
// a bounded 3-attempt retry loop -- including a missing_project_key check
// that drives the LLM to add its own project filter via corrective feedback,
// replacing this node's old regex-based project-clause injection.
const base = $items("Build Cypher Prompt")[0].json;
const result = $json;
if (!result || result.valid !== true || !result.cypher) {
  const violations = (result && result.violations) || [];
  throw new Error('Cypher generation failed validation after retries: ' + JSON.stringify(violations));
}
let cypher = result.cypher.trim();
if (!/\bLIMIT\b/i.test(cypher)) {
  cypher = cypher + ' LIMIT 50';
}
return [{ json: { ...base, cypher } }];

const input = $items("Set Input Defaults")[0].json;
const cypher = $items("Parse Cypher")[0].json.cypher;
const result = $json?.result?.data || {};
const records = Array.isArray(result.records) ? result.records : [];
const sample = records.slice(0, 30);
const prompt = [
  'You are a concise assistant answering questions about a Neo4j graph.',
  'Use the query results to answer. If results are empty, say no data found.',
  'If results include rule text with numeric values, extract the most relevant number and unit.',
  'Respond in plain language, 1-3 sentences.',
  'Question:',
  input.prompt_text,
  'Cypher:',
  cypher,
  'Results (JSON):',
  JSON.stringify(sample)
].join('\\n');
return [{ json: { ...input, cypher, records: sample, answer_prompt: prompt } }];

const base = $items("Build Answer Prompt")[0].json;
const raw = $json.text !== undefined ? $json.text : ($json.body !== undefined ? $json.body : $json);
let parsed = raw;
try {
  if (typeof raw === 'string') {
    const trimmed = raw.trim();
    const start = trimmed.indexOf('{');
    const end = trimmed.lastIndexOf('}');
    const jsonText = (start !== -1 && end !== -1) ? trimmed.slice(start, end + 1) : trimmed;
    parsed = JSON.parse(jsonText);
  }
} catch (_) {}
let answer = '';
if (parsed && typeof parsed === 'object') {
  answer = parsed.answer || parsed.response || parsed.text || '';
} else if (typeof parsed === 'string') {
  answer = parsed;
}
answer = (answer || '').trim();

const question = (base.prompt_text || '').toLowerCase();
const records = Array.isArray(base.records) ? base.records : [];

const findNumericSnippet = (text) => {
  if (!text || typeof text !== 'string') return '';
  const match = text.match(/(\d+(?:\.\d+)?)\s*(m|meter|meters|metre|metres|cm|mm|km|hours?|hrs?|days?)\b/i);
  if (match) return `${match[1]} ${match[2]}`;
  const paren = text.match(/\(([^\)]*\d+[^\)]*)\)/);
  if (paren) return paren[1];
  return '';
};

if (records.length && /\blist\b/.test(question) && /\brules\b/.test(question)) {
  const lines = [];
  for (const rec of records) {
    if (!rec || typeof rec !== 'object') continue;
    const id = rec.id || '';
    const name = rec.kind || '';
    const text = rec.text || '';
    const swrl = '';
    const snippet = findNumericSnippet(text) || findNumericSnippet(swrl);
    const label = [id, name].filter(Boolean).join(' - ');
    const tail = snippet ? ` (${snippet})` : (text ? ` (${text})` : '');
    lines.push(`${label}${tail}`.trim());
  }
  if (lines.length && (!answer || !/\d/.test(answer))) {
    answer = lines.join('\n');
  }
}

if (!answer) {
  let textValue = '';
  for (const rec of records) {
    if (!rec || typeof rec !== 'object') continue;
    if (typeof rec.text === 'string') {
      textValue = rec.text;
      break;
    }
    for (const key of Object.keys(rec)) {
      const val = rec[key];
      if (typeof val === 'string' && /\d/.test(val)) {
        textValue = val;
        break;
      }
      if (val && typeof val === 'object' && typeof val.properties === 'object') {
        const propText = val.properties.text;
        if (typeof propText === 'string' && /\d/.test(propText)) {
          textValue = propText;
          break;
        }
      }
    }
    if (textValue) break;
  }
  if (textValue) {
    const match = textValue.match(/(\d+(?:\.\d+)?)\s*(m|meter|meters|metre|metres|cm|mm|km|hours?|hrs?|days?)\b/i);
    if (match && question.includes('height')) {
      answer = `The maximum height of buildings is ${match[1]} ${match[2]}.`;
    } else {
      answer = textValue;
    }
  }
}

return [{
  json: {
    status: 'ok',
    answer,
    cypher: base.cypher,
    records: base.records || []
  }
}];
